INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', $q$Certified EHR & Charting$q$, $q$Clinical documentation with specialty-specific templates, macros, and shortcuts for faster note-taking across dozens of specialties.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', $q$AI Note Assist$q$, $q$Generates structured, HIPAA-compliant clinical notes from voice or text input, reducing manual charting time for providers.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', $q$E-Prescribing & EPCS$q$, $q$Electronic prescribing including controlled substances, with medication history and interaction checks built into the workflow.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', $q$Medical Billing & Claims$q$, $q$Claims scrubbing, submission through a built-in clearinghouse, denial management, and patient statements for revenue cycle management.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', $q$Scheduling$q$, $q$Multi-provider, multi-location calendar management with automated appointment reminders and real-time eligibility checks.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', $q$Telehealth$q$, $q$HIPAA- and HITRUST-certified video visits supporting group sessions with up to 200 participants and dedicated provider URLs.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', $q$Patient Portal$q$, $q$Online scheduling, digital intake forms, secure messaging, and online bill payment for patients.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', $q$Practice Marketing Tools$q$, $q$Website, online review generation, and online scheduling tools carried over from the former PatientPop platform to help practices attract patients.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', $q$Mobile App$q$, $q$iPhone, iPad, and Apple Watch app for reviewing schedules, patient records, and clinical notes on the go.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', $q$Reporting & Analytics$q$, $q$Dashboards covering collections, claim denials, and practice performance metrics for owners and billing staff.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', $q$All-in-one platform combining EHR, billing, telehealth, and patient marketing under a single vendor$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', $q$Per-provider pricing lets non-clinical staff use the system without added per-seat costs$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', $q$Interface is generally described by reviewers as intuitive with a manageable learning curve$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', $q$AI Note Assist and SALT help speed up clinical documentation$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', $q$Broad specialty coverage with tailored templates for primary care, mental health, chiropractic, dermatology, and more$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', $q$Pricing is not published and requires a sales demo and custom quote$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', $q$Some reviewers report slow or unresponsive customer support at times$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', $q$Additional fees can apply for items like EPCS setup, PDMP integration, or data export$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', $q$Contract terms and cancellation policies have drawn complaints in reviews$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', $q$Not designed for large hospital systems or enterprise multi-specialty networks needing deep interoperability$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', $q$What is Tebra?$q$, $q$Tebra is a cloud-based EHR, practice management, billing, and patient engagement platform for independent healthcare practices, formed in 2021 from the merger of Kareo and PatientPop.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', $q$How much does Tebra cost?$q$, $q$Tebra does not publish fixed pricing. It prices per clinical provider and requires a custom quote based on specialty, provider count, and which modules (EHR, billing, telehealth, patient engagement) a practice selects.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', $q$Does Tebra offer a free trial?$q$, $q$Tebra's website does not advertise a self-serve free trial; prospective customers are directed to request a personalized demo instead.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', $q$Is there a Tebra mobile app?$q$, $q$Yes, Tebra offers a mobile app for iPhone, iPad, and Apple Watch that supports scheduling, patient record access, clinical charting, and e-prescribing.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', $q$What specialties does Tebra support?$q$, $q$Tebra supports a wide range of outpatient specialties including primary care, family medicine, pediatrics, mental health and psychiatry, psychology, chiropractic, dermatology, and podiatry, each with tailored templates.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', $q$Running clinical and billing operations from one system$q$, $q$A solo or small-group practice uses Tebra's EHR and billing modules together so charting, claims, and patient statements live in a single connected workflow instead of separate systems.$q$, $q$Independent physicians and small practice groups$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', $q$Outsourcing revenue cycle management$q$, $q$A practice without in-house billing expertise adds Tebra's billing services on top of the software so claims are managed by Tebra's billing team while the practice focuses on patient care.$q$, $q$Practices without dedicated billing staff$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', $q$Growing a new practice's patient base$q$, $q$A newly opened practice uses Tebra's website, online scheduling, and review-generation tools to build visibility and attract patients while managing visits in the same platform.$q$, $q$New or growing independent practices$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', $q$Offering virtual visits alongside in-person care$q$, $q$A practice adds Tebra's telehealth module to run video visits and virtual waiting rooms without adopting a separate telehealth vendor.$q$, $q$Practices expanding into virtual care$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', $q$EHR Starter$q$, $q$Custom quote$q$, $q$Per provider, per month$q$, $q$["Certified EHR technology","Clinical charting and documentation","Specialty-specific note templates"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', $q$Billing Starter$q$, $q$Custom quote$q$, $q$Per provider, per month$q$, $q$["Billing and claims submission","Payment processing","Basic practice management"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', $q$EHR+$q$, $q$Custom quote$q$, $q$Per provider, per month$q$, $q$["EHR and clinical charting","Medical billing and claims","Telehealth visits"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', $q$Practice Automation$q$, $q$Custom quote$q$, $q$Per provider, per month$q$, $q$["EHR, billing, and telehealth","Patient portal","Online scheduling and reputation management","Practice marketing tools"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Tebra is a cloud-based EHR and practice management platform built for independent healthcare practices. The company was formed in November 2021 through the merger of Kareo, a longtime medical billing and EHR provider founded in 2004, and PatientPop, a practice growth and patient engagement platform founded in 2014. That combined history is why Tebra ships with both deep clinical and billing functionality and marketing-oriented patient acquisition tools under one roof, rather than treating growth features as an afterthought bolted onto a clinical system.$q$, $q$The platform bundles certified EHR and clinical charting, medical billing and claims management, scheduling, telehealth, a patient portal, and website and reputation-management tools for growing a practice's patient base. Rather than pricing per user seat, Tebra prices per clinical provider, meaning an MD, DO, NP, or PA with an active patient panel, which lets front-desk staff, billers, and other non-clinical team members use the system without adding to the bill.$q$, $q$Tebra positions itself against both legacy EHR vendors built for hospital systems and narrower point solutions that only solve one piece of the puzzle, such as scheduling or billing alone. Its pitch is that a solo provider or small group can run clinical documentation, revenue cycle management, and patient marketing from a single vendor instead of stitching together several disconnected tools and paying multiple subscription fees.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', $q$who-tebra-is-for$q$, $q$Who Tebra Is For$q$, 2, ARRAY[$q$Tebra is aimed squarely at independent and small-to-midsize outpatient practices, from solo providers to multi-location groups with a handful of clinicians. It supports a broad range of specialties, including primary care, family medicine, internal medicine, pediatrics, mental health and psychiatry, psychology, chiropractic, dermatology, and podiatry, each with its own note templates, workflows, and billing codes tailored to that specialty's documentation needs.$q$, $q$It suits practices that want a single vendor for clinical, billing, and growth needs rather than separately purchasing an EHR, a clearinghouse, a scheduling tool, and a marketing agency. Practices that also want help filling their schedule, such as newer practices still building a patient base, benefit from Tebra's online booking, review generation, and website tools running alongside the clinical software in the same account.$q$, $q$Tebra is also a reasonable fit for practices that want to outsource some or all of their medical billing rather than manage claims fully in-house, since Tebra offers billing services as an add-on alongside its self-service billing software, giving smaller practices a path to add outsourced revenue-cycle help as they grow without switching platforms.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Large hospital systems, multi-specialty enterprise groups, or health networks with complex interoperability requirements are generally better served by enterprise EHR platforms such as Epic or Oracle Health, which offer deeper integration with hospital infrastructure, labs, and imaging systems than a practice-focused platform like Tebra is designed to provide.$q$, $q$Practices that need fully transparent, self-serve pricing before ever speaking to a salesperson may find Tebra frustrating, since pricing is quote-based and tied to a sales and demo process rather than published rate cards. Reviewers have also flagged contract terms, data-export fees, and cancellation friction as pain points worth negotiating carefully before signing a multi-year agreement.$q$, $q$Very small or budget-constrained solo practices exploring free or bare-bones low-cost EHR options, or practices with highly niche specialty documentation needs not well covered by Tebra's existing templates, may want to evaluate specialty-specific alternatives before committing, since Tebra is built for general and mid-size specialty outpatient care rather than every edge case.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Tebra's core is its certified EHR, offering clinical charting, e-prescribing (including EPCS for controlled substances), lab and imaging orders, and specialty-specific note templates. Its AI Note Assist feature can generate structured clinical documentation from voice or text input, and the SALT tool lets providers pull forward content from prior visits to speed up charting for follow-up appointments.$q$, $q$On the operations side, Tebra provides medical billing and revenue cycle management, including claims scrubbing and submission, a built-in clearinghouse, patient statements and online payments, and reporting on collections and claim denials. Scheduling tools support multi-provider and multi-location calendars, appointment reminders, and integrated eligibility checks so front-desk staff can verify coverage before a visit.$q$, $q$Patient-facing features round out the platform: a HIPAA- and HITRUST-certified telehealth solution supporting video visits with up to 200 participants, a patient portal for digital intake forms, secure messaging, and online payments, and marketing tools for practice websites, online reviews, and online scheduling to help independent practices attract and retain patients over time.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', $q$the-tebra-experience$q$, $q$The Tebra Experience$q$, 2, ARRAY[$q$Getting started with Tebra typically means requesting a demo and working with a sales representative to configure a plan around provider count, specialty, and which modules, such as EHR, billing, telehealth, or patient engagement, a practice needs, since pricing and packaging aren't published outright on the website and vary by claim volume and provider type.$q$, $q$User reviews consistently describe the day-to-day interface as intuitive, with straightforward menus and a manageable learning curve for staff who are new to the system, and the mobile app extends scheduling, charting, and e-prescribing to iPhone, iPad, and Apple Watch for providers who need to review a chart or sign off a note away from the office.$q$, $q$The more common complaints in reviews center on customer support responsiveness, occasional system slowdowns, and pricing friction such as add-on fees or the effort required to export data or exit a contract, so practices evaluating Tebra should read the contract terms and support service-level commitments closely during the sales process before signing.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
