INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6d4bf973-60bc-4423-b9e1-f29a29ba365a', $q$ZenoChat Assistant$q$, $q$A conversational AI assistant for drafting, rewriting, summarizing, and translating text, accessible via web app or embedded overlay.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6d4bf973-60bc-4423-b9e1-f29a29ba365a', $q$Browser Extension$q$, $q$Brings AI writing and editing tools directly into thousands of web apps, including email, docs, and CRM platforms, without switching tabs.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6d4bf973-60bc-4423-b9e1-f29a29ba365a', $q$Knowledge Bases$q$, $q$Upload PDFs or connect Google Drive and SharePoint so AI responses are grounded in company-specific documents and data.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6d4bf973-60bc-4423-b9e1-f29a29ba365a', $q$No-Code AI Agent Builder$q$, $q$Build multi-step automated workflows visually, chaining research, drafting, and formatting tasks without writing code.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6d4bf973-60bc-4423-b9e1-f29a29ba365a', $q$Model Hub$q$, $q$Route prompts across multiple large language models from providers such as OpenAI, Anthropic, and Google within a single interface.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6d4bf973-60bc-4423-b9e1-f29a29ba365a', $q$Templates Library$q$, $q$Dozens of pre-built templates for emails, ads, articles, and social posts to speed up common writing tasks.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6d4bf973-60bc-4423-b9e1-f29a29ba365a', $q$Web Search Integration$q$, $q$Lets the assistant pull in current information from the internet and cite sources within its generated responses.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6d4bf973-60bc-4423-b9e1-f29a29ba365a', $q$Data Analysis$q$, $q$Analyze spreadsheets and reports directly within the assistant for quick summaries and insights.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6d4bf973-60bc-4423-b9e1-f29a29ba365a', $q$API and Automation Integrations$q$, $q$Developer API plus integrations with Zapier, Make, and Pipedream for connecting TextCortex into broader workflows.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6d4bf973-60bc-4423-b9e1-f29a29ba365a', $q$Browser extension embeds AI assistance directly into thousands of existing web apps$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6d4bf973-60bc-4423-b9e1-f29a29ba365a', $q$Combines writing, knowledge search, and no-code automation in one platform$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6d4bf973-60bc-4423-b9e1-f29a29ba365a', $q$Model hub gives access to multiple underlying LLMs without separate subscriptions$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6d4bf973-60bc-4423-b9e1-f29a29ba365a', $q$Free plan available for light, occasional use before committing to a paid tier$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6d4bf973-60bc-4423-b9e1-f29a29ba365a', $q$Knowledge base and agent builder support more than basic text generation$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6d4bf973-60bc-4423-b9e1-f29a29ba365a', $q$Free tier's daily creation limits are restrictive for regular or high-volume use$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6d4bf973-60bc-4423-b9e1-f29a29ba365a', $q$Output quality can vary depending on which underlying model is selected$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6d4bf973-60bc-4423-b9e1-f29a29ba365a', $q$Broad browser extension permissions may concern privacy-conscious users$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6d4bf973-60bc-4423-b9e1-f29a29ba365a', $q$Knowledge base and agent features require setup time to configure well$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6d4bf973-60bc-4423-b9e1-f29a29ba365a', $q$Higher-volume Unlimited and Enterprise tiers add meaningful cost as usage scales$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('6d4bf973-60bc-4423-b9e1-f29a29ba365a', $q$What is TextCortex used for?$q$, $q$TextCortex is an AI writing and knowledge platform used for drafting, rewriting, and summarizing content, searching internal knowledge bases, and automating writing-related workflows through a browser extension, web app, and API.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('6d4bf973-60bc-4423-b9e1-f29a29ba365a', $q$Does TextCortex have a free plan?$q$, $q$Yes, TextCortex offers a free plan with a limited number of daily creations and access to core writing features, alongside paid Premium, Unlimited, and Enterprise tiers for higher usage and additional capabilities.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('6d4bf973-60bc-4423-b9e1-f29a29ba365a', $q$Which apps does the TextCortex browser extension work with?$q$, $q$The browser extension integrates with a large number of web platforms, including email clients, Google Docs, CRMs, and social media tools, letting users generate and edit text directly where they are typing.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('6d4bf973-60bc-4423-b9e1-f29a29ba365a', $q$Which AI models does TextCortex use?$q$, $q$TextCortex routes requests through a model hub that can draw on multiple large language models from providers such as OpenAI, Anthropic, and Google, rather than relying on a single proprietary model.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('6d4bf973-60bc-4423-b9e1-f29a29ba365a', $q$Is TextCortex suitable for teams and enterprises?$q$, $q$Yes, TextCortex offers knowledge base connections to sources like SharePoint and Google Drive, a no-code agent builder, and an Enterprise plan with custom pricing for organizations needing governance and priority support.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6d4bf973-60bc-4423-b9e1-f29a29ba365a', $q$Content and Social Media Drafting$q$, $q$Marketers and social media managers use TextCortex's templates and rewriting tools to produce first drafts of articles, ads, and social posts faster.$q$, $q$Content marketers and social media managers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6d4bf973-60bc-4423-b9e1-f29a29ba365a', $q$In-App Sales and Support Messaging$q$, $q$Sales and support teams use the browser extension to draft emails, CRM notes, and LinkedIn outreach directly inside the tools they already use.$q$, $q$Sales and customer support teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6d4bf973-60bc-4423-b9e1-f29a29ba365a', $q$Internal Knowledge Search$q$, $q$Teams upload documents and connect cloud storage so employees can query company-specific information through a conversational interface.$q$, $q$Operations and knowledge management teams$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6d4bf973-60bc-4423-b9e1-f29a29ba365a', $q$Workflow Automation with No-Code Agents$q$, $q$Businesses build multi-step agents that chain research, drafting, and formatting tasks without involving engineering resources.$q$, $q$Small business owners and agencies$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('6d4bf973-60bc-4423-b9e1-f29a29ba365a', $q$Free$q$, $q$$0$q$, $q$N/A$q$, $q$["Limited daily creations","Access to core writing features","Limited knowledge bases"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('6d4bf973-60bc-4423-b9e1-f29a29ba365a', $q$Premium$q$, $q$From $5.59/month (billed annually) or $6.99/month billed monthly$q$, $q$Monthly or annual$q$, $q$["150 to unlimited monthly creations (configurable)","Advanced LLM access","Knowledge base integrations","Web search"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('6d4bf973-60bc-4423-b9e1-f29a29ba365a', $q$Unlimited$q$, $q$From $83.99/month (billed annually) or $119.99/month billed monthly$q$, $q$Monthly or annual$q$, $q$["Unlimited custom agents","Unlimited knowledge bases","Up to 100 GB storage","Image generation and data analysis"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('6d4bf973-60bc-4423-b9e1-f29a29ba365a', $q$Enterprise$q$, $q$Custom$q$, $q$Custom$q$, $q$["Tailored deployment and governance","SSO and admin controls","Priority support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6d4bf973-60bc-4423-b9e1-f29a29ba365a', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$TextCortex is a Berlin-based AI company that builds a writing and knowledge platform centered on its ZenoChat assistant. Rather than confining users to a single web app, TextCortex ships a browser extension that layers AI generation, rewriting, summarizing, and translation on top of thousands of existing tools, from Gmail and Google Docs to CRMs and social platforms.$q$, $q$Beyond text generation, the product has expanded into a broader AI infrastructure suite: knowledge bases that ingest PDFs, websites, and Google Drive or SharePoint content, a no-code agent builder for automating multi-step workflows, and a model hub that routes prompts across LLMs from providers like OpenAI, Anthropic, and Google.$q$, $q$This positions TextCortex less as a single-purpose writing tool and more as an AI layer teams can plug into their daily software stack, aiming to reduce tab-switching and centralize AI-assisted work, research, and knowledge retrieval in one interface.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6d4bf973-60bc-4423-b9e1-f29a29ba365a', $q$who-textcortex-is-for$q$, $q$Who TextCortex Is For$q$, 2, ARRAY[$q$Content marketers, social media managers, and copywriters who produce high volumes of short- and long-form content will find the templates, rewriting tools, and tone controls useful for speeding up first drafts and repurposing existing material.$q$, $q$Customer support, sales, and business development teams benefit from the browser extension, since it lets them draft emails, LinkedIn messages, and CRM notes directly inside the tools they already use, without copying text back and forth from a separate chat window.$q$, $q$Small and mid-sized businesses and agencies that want a lighter-weight alternative to building custom LLM tooling are also a strong fit, particularly those interested in the knowledge base and no-code agent features for internal documentation search or repetitive workflow automation.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6d4bf973-60bc-4423-b9e1-f29a29ba365a', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Developers or teams looking for a dedicated coding assistant, or a deeply specialized tool for a narrow use case like SEO content briefs or long-form book writing, may find TextCortex's general-purpose toolkit less focused than category-specific alternatives.$q$, $q$Organizations that already have a mature enterprise AI deployment, such as a custom internal GPT wrapper or a Microsoft Copilot rollout, may see feature overlap and should weigh whether adding another AI layer creates redundancy rather than added value.$q$, $q$Users who are uncomfortable installing a browser extension with broad permissions across web apps, or who need to stay entirely within a strict free tier, should also think carefully, since the free plan's daily creation limits will feel restrictive for regular, high-volume use.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6d4bf973-60bc-4423-b9e1-f29a29ba365a', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$The core of the product is ZenoChat, a conversational AI assistant with web search, document analysis, and a library of writing templates covering emails, articles, ads, and social posts, all accessible through a chat interface or the browser extension overlay.$q$, $q$Knowledge Bases let users upload files or connect cloud storage and enterprise sources so responses are grounded in company-specific information, while the no-code agent builder allows non-technical users to chain steps like research, drafting, and formatting into a reusable automated workflow.$q$, $q$Additional capabilities include a model hub for choosing between multiple underlying LLMs, basic data analysis for spreadsheets, image generation, a Mac desktop app, and integrations with automation platforms like Zapier and Make, plus a developer API for custom implementations.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6d4bf973-60bc-4423-b9e1-f29a29ba365a', $q$the-textcortex-experience$q$, $q$The TextCortex Experience$q$, 2, ARRAY[$q$Getting started is straightforward: sign up, install the browser extension, and the assistant becomes available as a small overlay inside most text fields across the web, which shortens the learning curve compared to tools that require constant context-switching to a separate tab.$q$, $q$Day-to-day use tends to center on quick, in-context edits and drafts rather than long uninterrupted writing sessions, and users who lean on the knowledge base and agent builder report a steeper but worthwhile learning curve as those features require some initial setup and organization.$q$, $q$Overall sentiment in user reviews is generally positive around speed and convenience, with the most common friction points being the daily creation caps on lower tiers and occasional inconsistency in output quality depending on which underlying model is selected for a given task.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6d4bf973-60bc-4423-b9e1-f29a29ba365a', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
