INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6d4bf973-60bc-4423-b9e1-f29a29ba365a', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6d4bf973-60bc-4423-b9e1-f29a29ba365a', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6f813de0-d2a3-471f-a9eb-5435220544a4', $q$Course Builder$q$, $q$Drag-and-drop editor for organizing video, text, PDFs, quizzes, and assignments into chapters with drip scheduling.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6f813de0-d2a3-471f-a9eb-5435220544a4', $q$Built-in Checkout & Payments$q$, $q$Native checkout supporting one-time purchases, payment plans, subscriptions, coupons, and order bumps without a separate payment integration.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6f813de0-d2a3-471f-a9eb-5435220544a4', $q$Communities & Memberships$q$, $q$Discussion spaces and membership tiers that can be bundled with course content for ongoing engagement.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6f813de0-d2a3-471f-a9eb-5435220544a4', $q$Live Cohorts & Coaching$q$, $q$Zoom-integrated live sessions and cohort-based courses alongside self-paced content.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6f813de0-d2a3-471f-a9eb-5435220544a4', $q$Completion Certificates & Grading$q$, $q$Automated certificates, quizzes, and instructor grading tools to track student progress.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6f813de0-d2a3-471f-a9eb-5435220544a4', $q$Student Mobile App$q$, $q$Native iOS and Android apps that let students watch courses and participate in communities on the go.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6f813de0-d2a3-471f-a9eb-5435220544a4', $q$Custom Domain & Branding$q$, $q$White-label course sites with a custom domain and, on higher plans, removal of Thinkific branding.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6f813de0-d2a3-471f-a9eb-5435220544a4', $q$API & Integrations$q$, $q$API access on Grow and above plus an app marketplace for connecting email, CRM, and marketing tools.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6f813de0-d2a3-471f-a9eb-5435220544a4', $q$Analytics & Reporting$q$, $q$Dashboards covering sales, student engagement, and course completion metrics.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6f813de0-d2a3-471f-a9eb-5435220544a4', $q$Branded Mobile App$q$, $q$Optional add-on that publishes a creator's own white-label learning app to the App Store and Google Play.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6f813de0-d2a3-471f-a9eb-5435220544a4', $q$All-in-one hosting, course delivery, and checkout without needing separate payment processing tools$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6f813de0-d2a3-471f-a9eb-5435220544a4', $q$No-code course builder that is approachable for non-technical creators$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6f813de0-d2a3-471f-a9eb-5435220544a4', $q$Native support for communities, memberships, and live cohorts alongside traditional courses$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6f813de0-d2a3-471f-a9eb-5435220544a4', $q$Student mobile apps and an optional white-label branded app option$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6f813de0-d2a3-471f-a9eb-5435220544a4', $q$Strong marketing and commerce features like payment plans, coupons, and abandoned-cart recovery$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6f813de0-d2a3-471f-a9eb-5435220544a4', $q$No permanent free plan, only a time-limited free trial$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6f813de0-d2a3-471f-a9eb-5435220544a4', $q$Advanced enterprise features like SSO and SCORM live behind the separate Thinkific Plus tier$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6f813de0-d2a3-471f-a9eb-5435220544a4', $q$Higher-tier features such as API access and phone support require upgrading past the entry plan$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6f813de0-d2a3-471f-a9eb-5435220544a4', $q$Mobile app is limited to content consumption and does not support quizzes or authoring$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6f813de0-d2a3-471f-a9eb-5435220544a4', $q$Deep customization of site design can require HTML/CSS knowledge on lower plans$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('6f813de0-d2a3-471f-a9eb-5435220544a4', $q$Does Thinkific offer a free plan?$q$, $q$Thinkific does not offer a permanent free plan. Instead, it provides a time-limited free trial so creators can build and test a course before subscribing to a paid plan.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('6f813de0-d2a3-471f-a9eb-5435220544a4', $q$What is the difference between Thinkific and Thinkific Plus?$q$, $q$Thinkific is the standard, self-serve platform with tiered monthly plans, while Thinkific Plus is a separate, custom-priced enterprise offering with dedicated support, SSO, SCORM, and advanced compliance features aimed at large organizations.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('6f813de0-d2a3-471f-a9eb-5435220544a4', $q$Can students access Thinkific courses on mobile?$q$, $q$Yes, Thinkific offers native iOS and Android apps for students to watch course content and participate in communities, and creators can add a white-label branded mobile app for an additional fee.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('6f813de0-d2a3-471f-a9eb-5435220544a4', $q$Does Thinkific charge transaction fees?$q$, $q$Thinkific has moved toward eliminating transaction fees on most current plans in primary markets like the US, though fee structures can vary by plan and payment gateway, so creators should confirm current terms on the pricing page.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('6f813de0-d2a3-471f-a9eb-5435220544a4', $q$Can I sell memberships and communities, not just courses, on Thinkific?$q$, $q$Yes, Thinkific supports memberships, subscriptions, and community spaces alongside traditional courses, allowing creators to combine recurring revenue models with content delivery in one site.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6f813de0-d2a3-471f-a9eb-5435220544a4', $q$Launching a First Online Course$q$, $q$A subject-matter expert uses Thinkific's templates and course builder to package existing knowledge into a paid course with checkout and student access handled automatically.$q$, $q$Independent coaches and first-time creators$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6f813de0-d2a3-471f-a9eb-5435220544a4', $q$Running a Paid Community with Content Drips$q$, $q$A creator combines a discussion community with scheduled course content to keep members engaged between live sessions.$q$, $q$Membership-site operators and community builders$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6f813de0-d2a3-471f-a9eb-5435220544a4', $q$Scaling a Cohort-Based Coaching Program$q$, $q$A coaching business uses live Zoom-integrated cohorts alongside self-paced modules and certificates to run structured, recurring programs.$q$, $q$Coaches and training businesses$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6f813de0-d2a3-471f-a9eb-5435220544a4', $q$Selling B2B Training with Group Access$q$, $q$A training company uses group orders, invoicing, and admin roles to sell bulk course access to corporate clients.$q$, $q$B2B training providers and consultancies$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('6f813de0-d2a3-471f-a9eb-5435220544a4', $q$Basic$q$, $q$$36/month billed annually ($49/month billed monthly)$q$, $q$Monthly or annual$q$, $q$["Unlimited courses","1 community","5 digital products","Custom domain","Abandoned-cart recovery","100 GB video bandwidth"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('6f813de0-d2a3-471f-a9eb-5435220544a4', $q$Start$q$, $q$$74/month billed annually ($99/month billed monthly)$q$, $q$Monthly or annual$q$, $q$["Everything in Basic","Live cohorts and coaching","Completion certificates","Payment plans","Memberships and subscriptions","200 GB video bandwidth"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('6f813de0-d2a3-471f-a9eb-5435220544a4', $q$Grow$q$, $q$$149/month billed annually ($199/month billed monthly)$q$, $q$Monthly or annual$q$, $q$["Everything in Start","Thinkific branding removed","3 communities","API access","Phone and priority support","400 GB video bandwidth"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('6f813de0-d2a3-471f-a9eb-5435220544a4', $q$Plus$q$, $q$Custom pricing$q$, $q$Custom$q$, $q$["Dedicated support","Single sign-on","SCORM and learning paths","CRM integrations","Branded mobile app option","Custom analytics dashboards"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6f813de0-d2a3-471f-a9eb-5435220544a4', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Thinkific is a cloud-based learning commerce platform that lets entrepreneurs, coaches, and businesses create, market, and sell online courses, communities, and digital products without writing code. Founded in 2012 in Vancouver, Canada, it built its reputation on giving independent creators the publishing and commerce tools once reserved for large e-learning vendors, bundling a drag-and-drop course builder, video hosting, quizzes, certificates, and checkout into one subscription. Over more than a decade, the product has grown from a simple course-hosting tool into a broader learning commerce suite used by creators across dozens of countries.$q$, $q$At its core, Thinkific handles the two hardest parts of running an online education business: content delivery and payment collection. Creators structure video, PDF, quiz, and assignment content into a curriculum, then choose one-time, subscription, payment-plan, or bundle pricing, with Thinkific processing payments, taxes, and student access automatically. The platform has since expanded beyond individual courses into communities, memberships, and live cohort coaching, reflecting a broader shift among creators toward blending self-paced lessons with ongoing engagement rather than selling a single static product.$q$, $q$Thinkific is now a publicly traded company on the Toronto Stock Exchange, and its core product sits alongside a separate enterprise tier, Thinkific Plus, aimed at larger organizations with more complex compliance, security, and support needs. An app marketplace and integrations with email, CRM, and automation tools round out the ecosystem, letting creators connect the pieces Thinkific does not natively cover, such as advanced email automation, affiliate programs, or external analytics.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6f813de0-d2a3-471f-a9eb-5435220544a4', $q$who-thinkific-is-for$q$, $q$Who Thinkific Is For$q$, 2, ARRAY[$q$Thinkific is built for independent creators, coaches, consultants, and small-to-midsize businesses that want to package expertise into a paid course, community, or coaching program without hiring developers. Solopreneurs launching their first course benefit from the guided setup, prebuilt templates, and all-in-one hosting, checkout, and student experience, which removes the need to stitch together separate video hosting, payment, and email tools.$q$, $q$It also suits established brands, associations, and training businesses that need more structure as they scale, since higher plans add live cohorts, certifications, B2B group enrollment, admin roles, and API access for connecting to existing marketing or CRM stacks. Membership-site operators and community builders who want to combine content drips with discussion spaces find the community features useful for keeping members engaged between course launches.$q$, $q$Marketing-savvy creators who want granular control over funnels, upsells, and coupons tend to get the most value, since Thinkific's commerce tools, including order bumps, abandoned-cart recovery, and flexible payment plans, are a core strength rather than an afterthought. Creators who already run an audience on social media or email and simply need a reliable place to sell and deliver content also tend to be a strong fit.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6f813de0-d2a3-471f-a9eb-5435220544a4', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Thinkific is less suited to organizations needing deep, formal compliance training infrastructure, such as enterprise SCORM/xAPI reporting, advanced learning paths, or SSO out of the box, since those live mainly behind the separate, custom-priced Thinkific Plus tier rather than the standard plans that most individual creators sign up for.$q$, $q$Budget-conscious first-time creators who only want to test an idea before committing financially may find the lack of a permanent free plan a hurdle, since Thinkific offers a time-limited trial rather than an always-free tier, unlike some lighter-weight competitors that let creators host a course indefinitely at no cost.$q$, $q$Teams wanting a single tool for both live-cohort-style community engagement at scale and heavy academic-style assessment, such as proctored exams, detailed gradebooks, or plagiarism checks, may also outgrow Thinkific's native toolset and need third-party add-ons or a dedicated LMS instead. Developers looking for a fully headless, API-first platform to build a completely custom learning experience may also find Thinkific's opinionated, hosted structure more restrictive than they want.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6f813de0-d2a3-471f-a9eb-5435220544a4', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Thinkific's course builder supports video, text, PDFs, quizzes, surveys, assignments, and downloadable resources organized into chapters, with drip scheduling and completion certificates available on most plans. Built-in commerce tools include checkout pages, coupons, order bumps, payment plans, subscriptions, and abandoned-cart recovery, so creators can sell directly without a separate payment processor integration or third-party cart software.$q$, $q$Beyond courses, the platform supports communities and memberships, live coaching or cohort sessions via Zoom integration, and a student mobile app for iOS and Android. Higher tiers add API access, custom domains, white-labeled branding, priority support, and reporting on student engagement and revenue, along with more admin seats for teams that need to divide content, marketing, and support responsibilities.$q$, $q$Thinkific also offers an app store of third-party integrations spanning email marketing, CRM, affiliate management, and analytics, plus a branded mobile app add-on that lets creators publish their own app to the App Store and Google Play under their own name. On the top-tier Plus plan, additional capabilities like single sign-on, SCORM-based learning paths, and custom analytics dashboards extend the platform toward enterprise-grade training needs.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6f813de0-d2a3-471f-a9eb-5435220544a4', $q$the-thinkific-experience$q$, $q$The Thinkific Experience$q$, 2, ARRAY[$q$New users typically start from a template and are guided through adding lessons, setting a price, and connecting a payout method, with most schools launching within a few days rather than weeks. The admin dashboard groups course building, site design, marketing, and reporting into distinct sections, which keeps day-to-day management approachable even for non-technical creators, though deeper visual customization can require some comfort with HTML and CSS on lower-tier plans.$q$, $q$The student-facing side is clean and distraction-light, with a dedicated course player, progress tracking, and an optional community feed, and the experience carries over reasonably well to the mobile app, though authoring and quizzes remain web-only. Students generally find navigating between courses, communities, and their own progress straightforward, which helps keep completion rates healthy for creators running structured programs.$q$, $q$Support quality and response time scale with plan tier, with live chat and phone support reserved for higher-paid plans, and creators moving upmarket generally describe the transition as smooth since features are additive rather than requiring a platform migration. A large library of help-center articles, webinars, and creator community resources supplements direct support for those on entry-level plans.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6f813de0-d2a3-471f-a9eb-5435220544a4', '87a92d11-ee13-4164-9910-61410254388a') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6f813de0-d2a3-471f-a9eb-5435220544a4', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6f813de0-d2a3-471f-a9eb-5435220544a4', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6f813de0-d2a3-471f-a9eb-5435220544a4', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6f813de0-d2a3-471f-a9eb-5435220544a4', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('87506dfb-5657-49d7-8e5e-045ff26172f8', $q$Single sign-on (SSO)$q$, $q$SAML and OIDC-based SSO lets organizations authenticate learners through their existing identity provider instead of managing separate Thinkific credentials.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('87506dfb-5657-49d7-8e5e-045ff26172f8', $q$SCORM import and tracking$q$, $q$Existing SCORM packages can be imported and tracked natively, letting teams reuse legacy e-learning content without rebuilding it in Thinkific's authoring tools.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('87506dfb-5657-49d7-8e5e-045ff26172f8', $q$Learning paths$q$, $q$Courses and content can be sequenced into structured or personalized learning journeys that guide different learner segments toward specific outcomes.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('87506dfb-5657-49d7-8e5e-045ff26172f8', $q$AI teaching assistant$q$, $q$An AI-powered assistant, referred to by Thinkific as Thinker, answers learner questions inside the course experience to reduce reliance on human support.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('87506dfb-5657-49d7-8e5e-045ff26172f8', $q$Branded mobile app$q$, $q$A custom mobile app built and maintained by Thinkific gives learners access to courses, communities, and content from iOS and Android devices under the customer's own brand.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('87506dfb-5657-49d7-8e5e-045ff26172f8', $q$CRM integrations$q$, $q$Native, bidirectional sync with HubSpot and Salesforce is reserved for the Plus tier, feeding learner activity into existing marketing and sales systems.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('87506dfb-5657-49d7-8e5e-045ff26172f8', $q$Custom analytics and reporting$q$, $q$Configurable dashboards surface enrollment, engagement, quiz performance, and SCORM interaction data, with exportable views for stakeholders outside the platform.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('87506dfb-5657-49d7-8e5e-045ff26172f8', $q$REST API and webhooks$q$, $q$A full API with webhook support allows engineering teams to connect Thinkific Plus to internal tools, data warehouses, or other parts of a broader software stack.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('87506dfb-5657-49d7-8e5e-045ff26172f8', $q$Multiple custom domains and white-labeling$q$, $q$Plus accounts can run several fully white-labeled domains with complete design control across the learner-facing experience.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('87506dfb-5657-49d7-8e5e-045ff26172f8', $q$Dedicated onboarding and success management$q$, $q$A launch specialist guides initial setup and migration, followed by a named customer success manager and priority support for ongoing account management.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('87506dfb-5657-49d7-8e5e-045ff26172f8', $q$Enterprise security and identity features, including SSO and SCORM support, layered on top of a mature, easy-to-use course-building product$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('87506dfb-5657-49d7-8e5e-045ff26172f8', $q$Faster typical implementation timelines than many traditional enterprise LMS platforms, backed by a dedicated launch specialist$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('87506dfb-5657-49d7-8e5e-045ff26172f8', $q$Native CRM integrations with HubSpot and Salesforce that are not available on standard Thinkific plans$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('87506dfb-5657-49d7-8e5e-045ff26172f8', $q$Branded, fully maintained mobile app option for reaching learners outside the browser$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('87506dfb-5657-49d7-8e5e-045ff26172f8', $q$Dedicated customer success manager and priority support for ongoing account management$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('87506dfb-5657-49d7-8e5e-045ff26172f8', $q$No published pricing, so every prospective customer must go through a sales conversation before knowing the cost$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('87506dfb-5657-49d7-8e5e-045ff26172f8', $q$Overkill and unnecessary cost for individual creators or small course businesses already served by standard Thinkific plans$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('87506dfb-5657-49d7-8e5e-045ff26172f8', $q$Less specialized than dedicated corporate LMS vendors for complex compliance tracking or certification workflows$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('87506dfb-5657-49d7-8e5e-045ff26172f8', $q$Custom quotes and contract terms make budgeting and cross-vendor comparison harder than platforms with transparent tiers$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('87506dfb-5657-49d7-8e5e-045ff26172f8', $q$Advanced features like the AI assistant and CRM sync are locked behind the enterprise tier and unavailable to lower-tier Thinkific customers$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('87506dfb-5657-49d7-8e5e-045ff26172f8', $q$How is Thinkific Plus different from standard Thinkific plans?$q$, $q$Thinkific Plus adds enterprise features on top of the same core course-building platform, including SSO, SCORM import, learning paths, native HubSpot and Salesforce integrations, custom analytics, and dedicated onboarding and support that are not available on Thinkific's standard self-serve plans.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('87506dfb-5657-49d7-8e5e-045ff26172f8', $q$How much does Thinkific Plus cost?$q$, $q$Thinkific does not publish Plus pricing. Cost is quoted individually based on factors like seat count, required integrations, and support level, so organizations need to contact Thinkific's sales team for a custom quote.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('87506dfb-5657-49d7-8e5e-045ff26172f8', $q$Does Thinkific Plus support single sign-on and SCORM content?$q$, $q$Yes. Thinkific Plus includes SAML and OIDC-based single sign-on for identity management, along with the ability to import and track SCORM packages, which are not available on lower Thinkific tiers.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('87506dfb-5657-49d7-8e5e-045ff26172f8', $q$Who typically uses Thinkific Plus?$q$, $q$Thinkific Plus is generally used by mid-market and larger organizations running customer education, partner enablement, association or membership training, or employee onboarding programs at a scale that requires formal governance, security, and dedicated vendor support.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('87506dfb-5657-49d7-8e5e-045ff26172f8', $q$How long does it take to launch on Thinkific Plus?$q$, $q$Thinkific reports a median time-to-launch of roughly two months for Plus customers, supported by an assigned launch specialist, which is generally faster than the multi-month timelines associated with many traditional enterprise LMS implementations.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('87506dfb-5657-49d7-8e5e-045ff26172f8', $q$Customer education programs$q$, $q$Software and product companies use Thinkific Plus to build branded academies that teach customers how to use their product, aiming to reduce support tickets and improve retention.$q$, $q$B2B and B2C companies running formal customer education or academy programs$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('87506dfb-5657-49d7-8e5e-045ff26172f8', $q$Partner and channel training$q$, $q$Organizations with reseller, franchise, or affiliate networks use Thinkific Plus to standardize certification and enablement content across many external partners.$q$, $q$Companies managing partner, franchise, or channel networks$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('87506dfb-5657-49d7-8e5e-045ff26172f8', $q$Association and membership training$q$, $q$Associations and professional bodies use Thinkific Plus to deliver accredited courses and continuing education to members, often integrated with existing membership and CRM systems.$q$, $q$Associations, certification bodies, and membership organizations$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('87506dfb-5657-49d7-8e5e-045ff26172f8', $q$Employee onboarding and internal training$q$, $q$Larger employers use Thinkific Plus to run structured onboarding and internal training programs, relying on SSO and role-based permissions to manage access across departments.$q$, $q$HR and learning and development teams at mid-market and large organizations$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('87506dfb-5657-49d7-8e5e-045ff26172f8', $q$Thinkific Plus$q$, $q$Contact for pricing$q$, $q$Custom / annual contract$q$, $q$["Single sign-on (SAML, OIDC)","SCORM import and tracking","Learning paths and AI teaching assistant","HubSpot and Salesforce integrations","Custom analytics dashboards","Dedicated launch specialist and customer success manager","Multiple custom domains and full white-labeling","10,000+ user capacity and additional admin accounts"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('87506dfb-5657-49d7-8e5e-045ff26172f8', $q$Branded Mobile App add-on$q$, $q$$199/month$q$, $q$Monthly (discount available on annual billing)$q$, $q$["Custom-branded iOS and Android app built and maintained by Thinkific","Learner access to courses, communities, and downloadable content on mobile","In-app enrollment and purchasing","Community feeds, direct messaging, and member profiles"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('87506dfb-5657-49d7-8e5e-045ff26172f8', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Thinkific Plus is the enterprise edition of Thinkific, the online course and learning commerce platform. While the standard Thinkific product is built for solo creators and small teams selling courses and memberships, Thinkific Plus repackages the same course-building engine with the security, integration, and support layer that larger organizations expect from a learning management system. It is aimed at companies running customer education, partner training, or employee onboarding programs at a scale where self-serve tooling and community forums are no longer enough.$q$, $q$The core idea behind Thinkific Plus is that organizations should not have to choose between a fast, modern authoring experience and enterprise-grade governance. Customers get the same drag-and-drop course builder, quiz tools, and content player as regular Thinkific, layered with single sign-on, SCORM support, learning paths, custom analytics, and dedicated account management. Thinkific frames this as a faster alternative to traditional enterprise LMS implementations, citing typical go-live timelines measured in weeks rather than the many months often associated with legacy corporate learning systems.$q$, $q$Because pricing and contract terms are negotiated directly with Thinkific's sales team, Thinkific Plus is positioned less as a self-service SaaS tier and more as a managed enterprise relationship, complete with an assigned launch specialist, ongoing customer success support, and access to solutions engineers for custom integration work. This makes it a distinct product decision from choosing one of Thinkific's standard monthly plans, and it is evaluated on different criteria: total cost of ownership, security posture, integration depth, and vendor support rather than sticker price alone.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('87506dfb-5657-49d7-8e5e-045ff26172f8', $q$who-thinkific-plus-is-for$q$, $q$Who Thinkific Plus Is For$q$, 2, ARRAY[$q$Thinkific Plus is built for mid-market and larger organizations that need to deliver training to audiences outside their own employee base, or to a workforce large enough to require formal governance. Typical buyers include companies running customer or partner education programs, associations and membership organizations training their members, franchise and multi-location businesses standardizing onboarding, and B2B software companies using education as a customer success or retention lever.$q$, $q$It also suits organizations with existing compliance, security, or identity requirements, such as a mandate for single sign-on through an identity provider, a need to import legacy SCORM content rather than rebuild it, or a requirement to prove data residency and SOC 2-level controls to their own customers or auditors. Teams that already use HubSpot or Salesforce as a system of record benefit from the native CRM sync that Thinkific reserves for the Plus tier, since it lets learner activity feed directly into existing marketing and sales workflows.$q$, $q$Finally, Thinkific Plus tends to fit organizations that value a guided, supported rollout over pure self-service. Buyers who want a named customer success manager, a defined launch process, and a support team held to a service-level response standard are the clearest fit, especially when the program being launched is public-facing, revenue-generating, or tied to brand reputation and cannot afford a rocky implementation.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('87506dfb-5657-49d7-8e5e-045ff26172f8', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Individual creators, coaches, and small course businesses are generally not a fit for Thinkific Plus. The standard Thinkific plans already cover course hosting, payments, and basic marketing tools at a fraction of the cost, and most solo sellers will never need SSO, SCORM import, or a dedicated success manager, making Plus unnecessary overhead for that segment.$q$, $q$Organizations with a tight, fixed budget or a preference for transparent, published pricing may also find Thinkific Plus frustrating, since every quote requires a sales conversation and there is no public price list to benchmark against internally before that call happens. Teams that want to self-serve their way from trial to paid plan without a procurement cycle are better served by Thinkific's standard tiers or a lighter-weight competitor.$q$, $q$Companies whose primary need is a full-featured corporate LMS with deep compliance tracking, complex certification workflows, or extensive third-party content marketplace integrations may find that dedicated enterprise LMS vendors offer more specialized functionality in those specific areas. Thinkific Plus is strongest as a learning commerce and customer education platform with enterprise trimmings, rather than as a pure compliance-training system of record.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('87506dfb-5657-49d7-8e5e-045ff26172f8', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At the identity and security layer, Thinkific Plus adds single sign-on via SAML and OIDC, granular user roles and permissions, and infrastructure described as meeting SOC 2 Type II and GDPR expectations. On the content side, it supports SCORM import and tracking so organizations can bring existing e-learning modules into the platform rather than rebuilding them from scratch, alongside structured or personalized learning paths that sequence content for different learner segments.$q$, $q$Plus-specific commercial and engagement tools include native CRM integrations with HubSpot and Salesforce, a custom-branded mobile app built and maintained by Thinkific, digital badges for recognizing learner achievement, and an AI-powered assistant intended to answer learner questions and reduce support load. A full REST API with webhooks is available for teams that want to connect Thinkific Plus into internal systems, data warehouses, or other parts of a broader martech and product stack.$q$, $q$On the operations side, Thinkific Plus customers get custom analytics dashboards, expanded seat and admin allowances, multiple custom domains with full white-labeling, and a services layer that includes a launch specialist for onboarding, a dedicated customer success manager afterward, and access to solutions engineers for more involved integration or migration work.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('87506dfb-5657-49d7-8e5e-045ff26172f8', $q$the-thinkific-plus-experience$q$, $q$The Thinkific Plus Experience$q$, 2, ARRAY[$q$Adopting Thinkific Plus typically starts with a sales and solutions consultation rather than a self-serve signup, since pricing, seat counts, and included services are scoped to the buyer's situation. From there, Thinkific assigns a launch specialist to guide migration of existing content, configuration of SSO and domains, and setup of learning paths, with the company citing a median time-to-launch of roughly two months for Plus customers, well under the multi-month timelines often associated with traditional enterprise LMS rollouts.$q$, $q$Once live, day-to-day use of Thinkific Plus feels close to standard Thinkific for course creators and administrators, since the authoring tools, course player, and community features are shared across the product line. What differs is the operational layer: administrators manage more granular roles, watch custom analytics dashboards for enrollment and engagement trends, and lean on a dedicated customer success manager and priority support channel rather than the self-service help center used by smaller accounts.$q$, $q$Ongoing relationships with Thinkific Plus tend to be evaluated the way any enterprise vendor is: uptime and support responsiveness, the depth of the CRM and API integrations in production, and whether the platform continues to scale as course catalogs, learner counts, and admin teams grow. Public review sites show generally positive sentiment toward the platform's support quality and ease of use, which lines up with Thinkific's own emphasis on service as a differentiator against larger, more self-service enterprise LMS competitors.$q$]::text[], 4);
