INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('87506dfb-5657-49d7-8e5e-045ff26172f8', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6e610684-65a5-4699-9418-e1149b45dc11', $q$Live Chat Widget$q$, $q$A customizable website chat widget with real-time visitor monitoring, live typing previews, canned responses, and automatic chat assignment.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6e610684-65a5-4699-9418-e1149b45dc11', $q$Lyro AI Agent$q$, $q$A conversational AI agent trained on a business's help center and FAQs that automatically answers routine customer questions and hands off complex ones to a human.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6e610684-65a5-4699-9418-e1149b45dc11', $q$Flows Automation Builder$q$, $q$A no-code, drag-and-drop editor for building chatbot conversation trees and behavior-triggered automations like cart abandonment prompts and lead capture.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6e610684-65a5-4699-9418-e1149b45dc11', $q$Helpdesk Ticketing$q$, $q$A ticketing system that organizes and tracks customer issues across channels, with dashboards for response time and satisfaction metrics.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6e610684-65a5-4699-9418-e1149b45dc11', $q$Multichannel Inbox$q$, $q$A unified inbox that brings together website chat, email, Instagram, Facebook Messenger, and WhatsApp conversations.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6e610684-65a5-4699-9418-e1149b45dc11', $q$Analytics and Reporting$q$, $q$Dashboards covering conversation volume, response times, customer satisfaction, and team performance.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6e610684-65a5-4699-9418-e1149b45dc11', $q$Third-Party Integrations$q$, $q$Native connections to ecommerce platforms, CRMs, and marketing tools including Shopify, WooCommerce, HubSpot, Klaviyo, Mailchimp, and Google Analytics.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6e610684-65a5-4699-9418-e1149b45dc11', $q$Multilingual Support$q$, $q$Chat widget language packs plus a Lyro AI agent that understands and responds in dozens of languages for global customer bases.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6e610684-65a5-4699-9418-e1149b45dc11', $q$Mobile and Desktop Apps$q$, $q$Native desktop and mobile apps that let support agents manage conversations away from the browser dashboard.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6e610684-65a5-4699-9418-e1149b45dc11', $q$API and Custom Branding$q$, $q$OpenAPI access and custom branding options on higher-tier plans for teams that want to extend or white-label the platform.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6e610684-65a5-4699-9418-e1149b45dc11', $q$Free plan and low-cost entry tiers make it accessible for small businesses and solo founders$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6e610684-65a5-4699-9418-e1149b45dc11', $q$Lyro AI agent can meaningfully reduce repetitive support tickets once trained on good content$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6e610684-65a5-4699-9418-e1149b45dc11', $q$No-code Flows builder lets non-technical teams set up chatbot automation quickly$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6e610684-65a5-4699-9418-e1149b45dc11', $q$Native integrations with major ecommerce platforms simplify setup for online stores$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6e610684-65a5-4699-9418-e1149b45dc11', $q$Unified inbox covers chat, email, and social messaging channels in one place$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6e610684-65a5-4699-9418-e1149b45dc11', $q$Conversation-based billing plus separate AI and Flows add-ons can make real costs harder to predict$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6e610684-65a5-4699-9418-e1149b45dc11', $q$Advertised base prices don't include AI features, which are billed separately$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6e610684-65a5-4699-9418-e1149b45dc11', $q$Limited depth for large enterprises needing complex routing or workforce management$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6e610684-65a5-4699-9418-e1149b45dc11', $q$Lyro AI accuracy depends heavily on how well-maintained the connected knowledge base is$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6e610684-65a5-4699-9418-e1149b45dc11', $q$No native voice or full contact-center capabilities beyond chat and messaging$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('6e610684-65a5-4699-9418-e1149b45dc11', $q$Does Tidio have a free plan?$q$, $q$Yes, Tidio offers a free plan that includes a limited number of billable conversations per month, basic live chat and ticketing features, and a one-time allotment of Lyro AI conversations.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('6e610684-65a5-4699-9418-e1149b45dc11', $q$What is Lyro and how does it work?$q$, $q$Lyro is Tidio's AI conversational agent. It learns from a business's existing help center articles and FAQs to answer routine customer questions automatically, escalating to a human agent when it can't resolve a query.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('6e610684-65a5-4699-9418-e1149b45dc11', $q$Which platforms does Tidio integrate with?$q$, $q$Tidio integrates with ecommerce platforms like Shopify, WooCommerce, and BigCommerce, along with CRM and marketing tools such as HubSpot, Klaviyo, Mailchimp, and Google Analytics, among others.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('6e610684-65a5-4699-9418-e1149b45dc11', $q$Is Tidio suitable for large enterprises?$q$, $q$Tidio is generally better suited to small and mid-sized businesses. Large enterprises with high support volume and complex routing needs may find its feature depth and per-conversation pricing model limiting at scale.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('6e610684-65a5-4699-9418-e1149b45dc11', $q$Is there a free trial for paid plans?$q$, $q$Yes, Tidio offers a free trial period on its paid plans, and the free plan itself can be used indefinitely without a credit card.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6e610684-65a5-4699-9418-e1149b45dc11', $q$Ecommerce Customer Support$q$, $q$Online stores install the live chat widget alongside Lyro AI to answer order status, shipping, and product questions automatically, reducing the load on human agents during peak shopping periods.$q$, $q$Ecommerce store owners and small retail brands$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6e610684-65a5-4699-9418-e1149b45dc11', $q$Lead Capture and Cart Recovery$q$, $q$Marketing teams use the Flows builder to trigger chat-based lead capture forms and cart abandonment messages based on visitor behavior, without needing developer support.$q$, $q$Marketing and growth teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6e610684-65a5-4699-9418-e1149b45dc11', $q$Multichannel Support Consolidation$q$, $q$Support teams connect Instagram, Facebook Messenger, WhatsApp, and email into a single Tidio inbox so agents can manage every customer conversation from one screen.$q$, $q$Small support teams managing multiple channels$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6e610684-65a5-4699-9418-e1149b45dc11', $q$Self-Serve FAQ Automation$q$, $q$Businesses train the Lyro AI agent on their help center content so common questions are answered instantly at any hour, freeing up staff time for more complex cases.$q$, $q$Small businesses and startups without 24/7 support staff$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('6e610684-65a5-4699-9418-e1149b45dc11', $q$Free$q$, $q$$0$q$, $q$monthly$q$, $q$["50 billable conversations/month","10 seats","Live chat, ticketing, and email management","100 Flows visitors/month","50 one-time Lyro AI conversations"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('6e610684-65a5-4699-9418-e1149b45dc11', $q$Starter$q$, $q$$24.17/month (billed monthly) or $290/year$q$, $q$monthly or annual$q$, $q$["100 billable conversations/month","10 seats","Live video calls","Basic analytics","100 Flows visitors/month"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('6e610684-65a5-4699-9418-e1149b45dc11', $q$Growth$q$, $q$From $49.17/month$q$, $q$monthly or annual$q$, $q$["Up to 2,000 billable conversations/month","10 seats","Advanced analytics and user permissions","Automatic chat assignment and replies","Up to 100,000 Flows visitors/month","Premium support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('6e610684-65a5-4699-9418-e1149b45dc11', $q$Plus$q$, $q$From $300/month plus usage fees$q$, $q$monthly or annual$q$, $q$["Custom conversation and seat limits","Dedicated success manager","Custom branding and departments","OpenAPI access","Multiproject support","Ticketing automations"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6e610684-65a5-4699-9418-e1149b45dc11', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Tidio is a customer service platform that bundles live chat, an AI conversational agent called Lyro, helpdesk ticketing, and multichannel messaging into a single dashboard. Founded in 2013 in Szczecin, Poland, the company has grown into a team spread across Poland and San Francisco while keeping its product centered on one goal: helping smaller businesses answer customer questions faster without hiring a large support team.$q$, $q$The platform's core pitch is unification. Instead of juggling separate tools for a website chat widget, an Instagram DM inbox, WhatsApp messages, and email tickets, Tidio routes all of it into one inbox that a small team can manage together. Lyro, the AI agent, sits on top of that inbox and is trained on a store's existing help articles and FAQs so it can resolve routine questions automatically and hand off anything it can't answer to a human.$q$, $q$Tidio positions itself as a lighter, faster-to-deploy alternative to enterprise support suites like Zendesk or Intercom. It leans heavily on ecommerce use cases, with native apps for Shopify, WooCommerce, and other store builders, a no-code chatbot flow editor, and pricing that starts free. That accessibility is the platform's main differentiator, though it comes with a pricing structure that gets more complex as usage and AI features scale up.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6e610684-65a5-4699-9418-e1149b45dc11', $q$who-tidio-is-for$q$, $q$Who Tidio Is For$q$, 2, ARRAY[$q$Tidio fits best for small and mid-sized ecommerce businesses that need a chat widget and automated FAQ handling without a dedicated support engineering team. Store owners on Shopify, WooCommerce, Wix, or BigCommerce can install the widget in minutes and get live chat, order-status lookups, and basic automation running the same day.$q$, $q$It also suits small businesses and startups that don't yet have a full customer support department but still need to keep response times low. Because Lyro can be trained on existing knowledge base content, a solo founder or a two-person support team can offload a meaningful share of repetitive tickets to the AI agent and focus their time on harder cases.$q$, $q$Marketing and growth teams who want proactive engagement — cart abandonment prompts, lead capture forms, and rule-based chatbot flows — are another good fit, since the visual Flows builder is designed to be used without writing code. Teams that want quick wins from automation, rather than a deeply customized enterprise workflow, tend to get the most value out of Tidio.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6e610684-65a5-4699-9418-e1149b45dc11', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Large enterprises with high support volume and complex routing needs may outgrow Tidio quickly. The platform is built around simplicity rather than the deep customization, role-based workflows, and large-scale queue management that bigger contact-center software offers, so support organizations with hundreds of agents will likely find it limiting.$q$, $q$Businesses that need phone support, full workforce management, or a true omnichannel contact center beyond chat and messaging should look elsewhere, since Tidio's feature set is concentrated on chat, chatbot automation, and lightweight ticketing rather than voice or advanced call-center operations.$q$, $q$Teams that need predictable, flat costs may also want to think twice. Because pricing is based on billable conversations, seats, and separate add-ons for the Lyro AI agent and the Flows automation builder, the effective monthly cost can climb well above the advertised starting price once conversation volume grows, which makes budgeting less straightforward than a simple per-seat model.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6e610684-65a5-4699-9418-e1149b45dc11', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At the center of Tidio is a customizable live chat widget with real-time visitor monitoring, live typing previews, canned responses, and automatic chat assignment, plus a shared inbox that also handles email and ticketing. Multichannel connections bring Instagram, Facebook Messenger, and WhatsApp conversations into the same view so nothing gets missed across channels.$q$, $q$The Lyro AI agent is the platform's flagship automation feature. It learns from a business's help center content and FAQs to answer routine customer questions in natural language, hands off to a human agent when it can't resolve something, and supports dozens of languages out of the box. Alongside it, the Flows builder offers a drag-and-drop, no-code way to design chatbot conversation trees, trigger messages based on visitor behavior, and automate tasks like order tracking or quote requests.$q$, $q$Rounding out the platform are helpdesk ticketing with performance analytics, user permissions and departments for larger teams, macros and automatic replies, and an integrations library covering ecommerce platforms, CRMs, and marketing tools such as HubSpot, Klaviyo, Mailchimp, and Google Analytics. Higher tiers add custom branding, an OpenAPI-based API, SSO, and dedicated success management.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6e610684-65a5-4699-9418-e1149b45dc11', $q$the-tidio-experience$q$, $q$The Tidio Experience$q$, 2, ARRAY[$q$Getting started with Tidio is generally quick: the widget installs via a script tag or a platform-specific app, and the free plan (with a no-credit-card trial on paid tiers) lets teams test live chat and basic automation before committing to a subscription. The dashboard is organized around a familiar inbox layout, which keeps the learning curve relatively shallow for non-technical users.$q$, $q$Setting up Lyro to answer questions well takes a bit more effort, since its accuracy depends on how complete and well-organized the connected knowledge base is. Teams that invest time in curating help content tend to see better automated resolution rates than those who turn it on with minimal setup. Tidio's help center and onboarding videos walk through this configuration in detail.$q$, $q$Overall, the experience favors businesses that want to be up and running fast rather than those seeking heavy customization. The trade-off shows up most clearly in billing: as conversation volume, AI usage, and visitor counts on Flows increase, users need to actively monitor which tier and add-ons they're on to avoid surprise costs, even though the day-to-day product experience itself stays straightforward.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6e610684-65a5-4699-9418-e1149b45dc11', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
