INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6e610684-65a5-4699-9418-e1149b45dc11', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$Automatic Time Tracking$q$, $q$Tracks work hours automatically across desktop, mobile, and browser sessions without requiring manual timers for every task.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$Screenshots & Activity Logging$q$, $q$Captures periodic screenshots and keyboard/mouse activity levels to give managers a visual record alongside logged hours.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$Web & App Usage Monitoring$q$, $q$Classifies time spent in specific applications and websites as productive, unproductive, or neutral for each employee.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$Productivity Ratings$q$, $q$Rolls up activity and usage data into productivity scores for individuals, teams, and the whole organization.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$Attendance & Schedules$q$, $q$Tracks clock-ins, shift adherence, breaks, and leave so managers can monitor attendance across distributed teams.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$Payroll Tools$q$, $q$Applies custom pay rates per user and converts tracked hours into payable amounts for employees and contractors.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$Client Login Access$q$, $q$Gives external clients a limited login to review time logs and reports on their own projects without full account access.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$AI-Powered Reports$q$, $q$Uses Benchmarks AI and Unusual Activity detection to flag anomalies such as mouse jigglers or irregular keyboard patterns.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$60+ Integrations$q$, $q$Connects with project management, communication, and accounting tools such as Asana, Trello, Slack, and QuickBooks.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$Open API & SSO$q$, $q$Offers API access, single sign-on, and automatic user provisioning for larger organizations on higher-tier plans.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$Detailed activity and productivity data, including screenshots, that helps justify billed or worked hours$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$Broad platform coverage across Windows, Mac, iOS, Android, and the web$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$Built-in payroll calculation reduces the need for a separate timesheet-to-payroll process$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$Client login access is useful for agencies and outsourcing firms that bill clients by the hour$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$Wide range of integrations with popular project management and communication tools$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$No free plan; every account requires a paid subscription after the trial ends$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$Per-user pricing can become expensive for larger teams once add-ons are included$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$Intense monitoring features can feel invasive and may hurt morale if rolled out without clear communication$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$Some users report desktop app installation issues, crashes, or occasional syncing problems$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$Project and task management features are comparatively basic next to dedicated project management tools$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$Does Time Doctor offer a free trial?$q$, $q$Yes. New accounts get a 14-day free trial of the Premium plan, and no credit card is required to start.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$Is there a free version of Time Doctor?$q$, $q$No, Time Doctor does not offer a permanent free plan. After the trial period, users must choose a paid plan to continue.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$What platforms does Time Doctor support?$q$, $q$Time Doctor is available as desktop apps for Windows and Mac, mobile apps for iOS and Android, and a browser-based web dashboard.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$Can employees see their own monitoring data?$q$, $q$Yes, employees generally have visibility into their own tracked time, screenshots, and activity data, not just managers.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$Does Time Doctor integrate with other tools?$q$, $q$Yes, it offers more than 60 integrations with project management, communication, and accounting tools, plus an open API on higher-tier plans.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$Outsourcing and BPO Workforce Tracking$q$, $q$Outsourcing firms use Time Doctor to log billable hours, capture screenshots, and give clients direct visibility into work performed on their projects.$q$, $q$Outsourcing and BPO companies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$Remote Agency Client Billing$q$, $q$Marketing and creative agencies track contractor and staff time against specific client projects and share reports through client login access.$q$, $q$Digital agencies and creative studios$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$Distributed Software Team Oversight$q$, $q$Engineering teams spread across countries use productivity ratings and activity reports to maintain visibility without constant synchronous check-ins.$q$, $q$Remote-first software and startup teams$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$Payroll for Global Contractors$q$, $q$HR and operations teams convert tracked hours into payable wages across contractors and employees on different pay rates and currencies.$q$, $q$HR and operations teams managing global contractors$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$Basic$q$, $q$$6.67/user/month billed annually ($8/user/month billed monthly)$q$, $q$Monthly or annual$q$, $q$["Automatic time tracking","Projects & tasks","Timeline report","Screenshots","Online/offline tracking","Groups & teams"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$Standard$q$, $q$$11.67/user/month billed annually ($14/user/month billed monthly)$q$, $q$Monthly or annual$q$, $q$["Everything in Basic","Schedules & attendance","Time approvals","Web & app usage reporting","Productivity ratings","Payroll","60+ integrations"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$Premium$q$, $q$$16.70/user/month billed annually ($20/user/month billed monthly)$q$, $q$Monthly or annual$q$, $q$["Everything in Standard","Benchmarks AI","Unusual Activity AI report","Video screen recording","Executive dashboard","Open API access","SSO","Client login access"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Monthly or annual$q$, $q$["All Premium features","Private cloud deployment","Customizable BI dashboards","Guided implementation","Professional services","Dedicated support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Time Doctor is a workforce analytics and time-tracking platform built for companies that manage remote, hybrid, or distributed teams. Founded in 2012 by remote-work pioneers Rob Rawson and Liam Martin, the company itself operates as a fully remote, async-first organization, which gives its product design a distinctly practical, in-the-trenches feel. At its core, Time Doctor combines automatic time tracking with screenshots, activity logging, and productivity scoring so that managers can see not just how many hours were logged, but what was actually worked on during that time.$q$, $q$The platform is delivered through desktop apps for Windows and Mac, mobile apps for iOS and Android, and a browser-based dashboard, all syncing to a central reporting engine. Teams use it to track billable hours for client work, monitor attendance and schedules, calculate payroll, and generate reports on web and application usage. Over time, Time Doctor has layered on AI-assisted features, including anomaly detection for unusual activity patterns and benchmarking against team norms, moving the product beyond a simple stopwatch into a broader productivity-intelligence tool.$q$, $q$Because monitoring employees is inherently sensitive, Time Doctor has built its reputation around configurability: administrators can dial monitoring intensity up or down per role, choose whether screenshots are blurred or full-resolution, and decide how much of that data individual employees can see about themselves. That flexibility is a major reason it has become a standard tool for outsourcing firms, agencies, and distributed engineering teams rather than a niche product for a single industry.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$who-time-doctor-is-for$q$, $q$Who Time Doctor Is For$q$, 2, ARRAY[$q$Time Doctor is best suited to organizations that manage people they cannot see in person and need objective data to fill that gap. Staffing agencies, outsourcing and BPO firms, and virtual assistant companies use it to prove billable hours to clients and to justify invoices with screenshots and activity logs. Marketing and creative agencies with contractor-heavy rosters use it similarly, pairing time tracking with client login access so customers can review their own project's hours directly.$q$, $q$Distributed software teams and startups with employees spread across many countries also rely on Time Doctor to keep a baseline of visibility without requiring constant check-in meetings. Its payroll integrations and attendance tracking make it a fit for HR and operations teams that need to convert tracked hours into payable wages across contractors on different pay structures. Call centers and other high-headcount, process-driven operations use its productivity ratings and schedule adherence reports to manage large hourly workforces at scale.$q$, $q$Managers who value data-backed accountability over trust-based management, and who are comfortable being transparent with employees about what is tracked, tend to get the most value from the platform. Companies already paying for per-seat monitoring tools and looking to consolidate time tracking, screenshots, and payroll into one subscription are also a strong match, since Time Doctor bundles those functions rather than requiring separate tools.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Time Doctor is a poor fit for small teams or solo freelancers who just want simple time tracking without monitoring, since there is no free plan and the pricing is built around per-user seats that add up quickly for larger headcounts. Businesses with a strong trust-first culture, or those in jurisdictions with strict employee-monitoring or privacy regulations, should evaluate the legal and cultural implications carefully before rolling out screenshot-based tracking.$q$, $q$Teams that need deep, granular project management, such as Gantt charts, dependencies, or complex resource planning, will find Time Doctor's project and task features comparatively basic compared to dedicated tools like Asana or Jira; it is built primarily as a monitoring and time-tracking layer that integrates with those tools rather than replacing them. Similarly, organizations that only need lightweight invoicing or a simple punch clock may find the feature set more than they need and the associated setup and change-management effort not worth it for their scale.$q$, $q$Companies wary of employee monitoring backlash should also be cautious. Reviewers consistently note that some employees find the always-on screenshots and activity scoring invasive, and rolling it out without clear communication about why and how data is used can hurt morale and trust, even when the underlying data is accurate.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At the center of Time Doctor's feature set is automatic time tracking paired with periodic desktop and application screenshots, giving managers a visual record of work alongside the raw hours logged. Web and app usage monitoring classifies time spent in different applications and websites as productive, unproductive, or neutral, feeding into a productivity rating for each employee or team. Attendance, schedules, and break tracking round out the workforce-management side, letting managers see who clocked in late, took extended breaks, or deviated from an assigned shift.$q$, $q$Payroll functionality lets administrators set different pay rates per employee or contractor and export tracked hours directly into payable amounts, while over 60 integrations connect Time Doctor to project management, communication, and accounting tools such as Asana, Trello, Slack, and QuickBooks. Higher-tier plans add AI-driven features like Benchmarks AI for comparing performance against peers, an Unusual Activity report that flags suspicious patterns such as mouse jigglers or irregular keyboard input, and video screen recording for a more complete activity record.$q$, $q$For client-facing businesses, a dedicated client login lets external stakeholders view time logs and reports for their own projects without full account access, which is particularly useful for agencies and outsourcing firms that need to justify invoiced hours. An open API, single sign-on, and private cloud deployment options on the Enterprise plan extend the platform to larger organizations with existing identity and infrastructure requirements.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$the-time-doctor-experience$q$, $q$The Time Doctor Experience$q$, 2, ARRAY[$q$Using Time Doctor day to day starts with installing a lightweight desktop or mobile app that runs in the background, prompting users to select a task or project before tracking begins. Screenshots and activity data accumulate automatically, and employees generally have some visibility into their own tracked data, which softens the sense of being watched blindly. Managers, meanwhile, work from a web dashboard packed with reports: timelines, productivity summaries, attendance logs, and payroll exports.$q$, $q$New users typically start on a 14-day free trial of the Premium plan with no credit card required, giving teams a chance to test the fuller feature set, including AI reports and video recording, before committing to a paid tier. Reviewers frequently describe the interface as functional and information-dense rather than flashy, prioritizing clear reporting over visual polish, and note that the learning curve is manageable for administrators but requires some upfront configuration to match monitoring intensity to company culture.$q$, $q$Overall, the experience skews toward data-driven oversight rather than lightweight self-tracking. Teams that invest a little time in setting sensible defaults, communicating monitoring policies clearly, and using the productivity data as a coaching tool rather than a surveillance stick tend to report the best outcomes, while teams that deploy it without that groundwork more often encounter employee pushback described in user reviews.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
