INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a14db145-0596-4250-b60b-dff6e306c021', $q$Automatic Memory Tracker$q$, $q$A background service that passively records time spent in desktop and web apps, documents, meetings, browser tabs and locations, with no manual timer required.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a14db145-0596-4250-b60b-dff6e306c021', $q$AI Timesheets$q$, $q$AI groups captured activity into draft time entries mapped to projects and clients, so a day's timesheet is largely built before the user reviews it.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a14db145-0596-4250-b60b-dff6e306c021', $q$Project Dashboard$q$, $q$A visual view of time spent, budget burn and progress across projects and clients, used to spot scope creep and margin risk early.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a14db145-0596-4250-b60b-dff6e306c021', $q$People Dashboard$q$, $q$Team-level view of capacity, workload and utilization built from actual tracked time rather than self-reported estimates.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a14db145-0596-4250-b60b-dff6e306c021', $q$Time Planning$q$, $q$Forecast and schedule upcoming work using historical tracked-time data to inform staffing and capacity decisions.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a14db145-0596-4250-b60b-dff6e306c021', $q$Billable Rates & Invoicing$q$, $q$Assign billable rates per person or project and route tracked, approved hours into invoicing and accounting workflows.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a14db145-0596-4250-b60b-dff6e306c021', $q$Reporting & Analytics$q$, $q$Configurable reports on utilization, profitability and project performance for operations and finance stakeholders.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a14db145-0596-4250-b60b-dff6e306c021', $q$Integrations$q$, $q$Native connections to tools including Asana, Jira, ClickUp, Linear, Google Calendar, Zoom, Xero, QuickBooks and Slack.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a14db145-0596-4250-b60b-dff6e306c021', $q$Privacy-First Tracking$q$, $q$Captured activity data stays visible only to the individual until they approve a time entry, distinguishing Timely from surveillance-style monitoring tools.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a14db145-0596-4250-b60b-dff6e306c021', $q$Cross-Platform Apps$q$, $q$Native Memory desktop clients for macOS and Windows, plus a web app and iOS and Android companion apps.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a14db145-0596-4250-b60b-dff6e306c021', $q$Fully automatic tracking removes the need to manually start, stop or remember timers$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a14db145-0596-4250-b60b-dff6e306c021', $q$Privacy-first design keeps detailed activity data hidden from managers until the user approves an entry$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a14db145-0596-4250-b60b-dff6e306c021', $q$AI-assisted timesheets can cut review time to just a couple of minutes a day$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a14db145-0596-4250-b60b-dff6e306c021', $q$Deep integrations with popular project management, calendar and accounting tools like Jira, Asana and QuickBooks$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a14db145-0596-4250-b60b-dff6e306c021', $q$Project and People dashboards give agencies and consultancies useful budget and capacity visibility$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a14db145-0596-4250-b60b-dff6e306c021', $q$No free plan — only a 14-day trial, then a paid subscription is required$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a14db145-0596-4250-b60b-dff6e306c021', $q$Per-seat pricing on the Unlimited plan can get costly for larger teams$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a14db145-0596-4250-b60b-dff6e306c021', $q$Interface is available in English only$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a14db145-0596-4250-b60b-dff6e306c021', $q$AI categorization can misclassify short activities, brief calls or fragmented tasks$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a14db145-0596-4250-b60b-dff6e306c021', $q$Some reviewers report a learning curve tuning projects and categorization rules to match real workflows$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('a14db145-0596-4250-b60b-dff6e306c021', $q$Does Timely have a free plan?$q$, $q$No. Timely offers a 14-day free trial with full feature access, but there is no permanent free tier — after the trial, a paid subscription (starting with the Starter plan) is required to keep using the product.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('a14db145-0596-4250-b60b-dff6e306c021', $q$What platforms does Timely support?$q$, $q$Timely is available as a web app, native Memory desktop clients for macOS and Windows, and companion mobile apps for iOS and Android.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('a14db145-0596-4250-b60b-dff6e306c021', $q$How does Timely's automatic tracking work, and is it invasive?$q$, $q$A background component called Memory passively logs time spent in apps, documents, meetings and browser tabs. Unlike keystroke-logging or screenshot-based monitoring tools, this activity data stays private to the individual until they choose to approve a time entry.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('a14db145-0596-4250-b60b-dff6e306c021', $q$What does Timely integrate with?$q$, $q$Timely connects with project management and communication tools such as Asana, Jira, ClickUp, Linear, Google Calendar, Zoom and Slack, as well as accounting platforms like Xero and QuickBooks.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('a14db145-0596-4250-b60b-dff6e306c021', $q$Who owns Timely and where is it based?$q$, $q$Timely is built by Memory AS (formerly Memory.ai), a Norwegian company headquartered in Oslo, founded in 2013 by product designer Mathias Mikkelsen.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a14db145-0596-4250-b60b-dff6e306c021', $q$Accurate client billing for agencies$q$, $q$Agencies use Timely's automatic tracking and AI timesheets to capture billable hours precisely and reduce disputes over invoiced time.$q$, $q$Creative and digital agencies billing clients hourly$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a14db145-0596-4250-b60b-dff6e306c021', $q$Utilization and margin protection for consultancies$q$, $q$Consultancies rely on Project and People dashboards to monitor budget burn and utilization in real time, protecting margins on fixed-fee and time-and-materials engagements.$q$, $q$Consulting and professional services firms$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a14db145-0596-4250-b60b-dff6e306c021', $q$Engineering time tracking without disrupting focus$q$, $q$SaaS and product teams use passive tracking to capture engineering and delivery time for reporting purposes without asking developers to run manual timers.$q$, $q$SaaS companies and product/engineering teams$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a14db145-0596-4250-b60b-dff6e306c021', $q$Capacity planning across a growing team$q$, $q$Operations leads use historical tracked-time data in the Time Planning module to forecast staffing needs and balance workload across a scaling team.$q$, $q$Operations and resource managers at mid-size teams$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('a14db145-0596-4250-b60b-dff6e306c021', $q$Starter$q$, $q$$11/user/month ($9/user/month billed annually)$q$, $q$Monthly or annual$q$, $q$["Up to 5 users, 20 projects","Automatic time tracking via Memory","AI Timesheets","Project dashboard","Basic reporting"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('a14db145-0596-4250-b60b-dff6e306c021', $q$Premium$q$, $q$$20/user/month ($16/user/month billed annually)$q$, $q$Monthly or annual$q$, $q$["Up to 50 users, unlimited projects","Everything in Starter","Project management and accounting integrations","Team management","Budgeting and cost management","Work/capacity planning"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('a14db145-0596-4250-b60b-dff6e306c021', $q$Unlimited$q$, $q$$28/user/month ($22/user/month billed annually)$q$, $q$Monthly or annual$q$, $q$["Unlimited users and projects","Everything in Premium","Capacity reporting","Overtime and undertime tracking","Support for 50+ currencies","Dedicated customer success"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('a14db145-0596-4250-b60b-dff6e306c021', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Contact sales$q$, $q$["Everything in Unlimited","Tailored onboarding and training","Monthly business reviews","Early access to new features","Priority support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a14db145-0596-4250-b60b-dff6e306c021', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Timely is an automatic time-tracking platform built by Memory AS (formerly Memory.ai), a company founded in 2013 in Oslo, Norway by product designer Mathias Mikkelsen. Mikkelsen started the company after burning out from manually logging billable hours at a design agency, and set out to build a tool that would track work without requiring anyone to start or stop a timer.$q$, $q$At the core of the product is a background service called Memory, which quietly records the desktop and web applications, documents, meetings, browser tabs and locations someone interacts with during the day. Timely's AI then groups that raw activity into draft time entries mapped to projects and clients, so a full day's timesheet is largely built before the user ever opens the app.$q$, $q$The pitch, as Timely puts it, is "auto-capture, auto-allocate, one-click approve" — activity data stays private to the person who generated it until they choose to submit an entry, which the company positions as a less invasive alternative to keystroke-logging or screenshot-based monitoring software. Timely is sold as a paid subscription with a 14-day free trial and no permanent free tier.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a14db145-0596-4250-b60b-dff6e306c021', $q$who-timely-is-for$q$, $q$Who Timely Is For$q$, 2, ARRAY[$q$Timely is built for teams whose revenue depends on billing hours accurately: agencies, consultancies and other professional-services firms that need to reconcile time spent against client budgets without chasing staff for manual timesheets. Its Project and People dashboards, budget tracking and billable-rate features are all oriented around protecting margins on client work.$q$, $q$It also suits SaaS and product organizations that want reliable time data on engineering and delivery work without disrupting focused work with manual start/stop timers — capacity planning, utilization reporting and resource forecasting are all built around the automatically captured data rather than self-reported estimates.$q$, $q$Teams of roughly 5 to 50 people who already use tools like Asana, Jira, ClickUp, Linear, Google Calendar or accounting software such as Xero and QuickBooks tend to get the most value, since Timely's integrations let tracked time flow directly into existing project and billing workflows rather than living in a separate silo.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a14db145-0596-4250-b60b-dff6e306c021', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Solo freelancers and very small teams who just want a free, lightweight stopwatch will likely find Timely more tool (and more expense) than they need, since there is no free plan — only a 14-day trial — and per-seat pricing starts at $11 a month. Simpler tools with generous free tiers are usually a better fit for that use case.$q$, $q$Organizations looking for active workforce surveillance — screenshots, keystroke logging, or continuous activity/idle scoring — will find Timely deliberately limited in this direction, since its whole privacy model is built around withholding granular activity detail from managers until the employee approves a time entry.$q$, $q$Teams operating outside English-speaking contexts should also be cautious, since Timely's interface is currently English-only. Reviewers also note that the AI sometimes misclassifies short activities, quick calls, or fragmented tasks, so teams whose work is made up mostly of brief, scattered interactions may find the automatic categorization less reliable than expected.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a14db145-0596-4250-b60b-dff6e306c021', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$The Memory tracker is the engine behind Timely: a desktop and browser component that passively captures time spent across apps, documents, meetings, browser tabs and even GPS locations, without requiring a manual timer. Timely's AI then converts that raw activity log into draft time entries, which power the AI Timesheets feature — a system designed to let people review and approve a completed day's timesheet in a couple of minutes instead of reconstructing it from memory.$q$, $q$On top of tracking, Timely provides a Project Dashboard for visualizing budget burn and progress per client or project, and a People Dashboard for team capacity, utilization and workload insights. A time-planning module lets managers forecast future work using historical tracked data rather than guesswork, and billable-rate and invoicing features connect tracked hours to client billing.$q$, $q$Timely rounds out the product with configurable reporting for profitability and utilization analysis, and integrations with tools like Asana, Jira, ClickUp, Linear, Google Calendar, Zoom, Xero, QuickBooks and Slack. The product is available through a web app, native Memory desktop clients for macOS and Windows, and companion iOS and Android mobile apps.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a14db145-0596-4250-b60b-dff6e306c021', $q$the-timely-experience$q$, $q$The Timely Experience$q$, 2, ARRAY[$q$Getting started with Timely means installing the Memory desktop app (or granting the browser access it needs), connecting calendars and integrations, and setting up projects and clients; tracking begins running in the background almost immediately afterward. Reviewers generally describe the onboarding as straightforward, though setting up categorization rules that match how a team actually works can take some iteration.$q$, $q$Day to day, the experience centers on a timeline-style review screen where a person scans the activity Memory captured, adjusts or splits entries where the AI grouped things incorrectly, and approves the result with a click. Users on review sites consistently praise the clean, colorful interface and the amount of manual entry it removes, particularly for accurate client billing and QuickBooks-style invoicing handoffs.$q$, $q$The most common complaints in reviews involve the AI occasionally misclassifying short activities or phone calls and some feature rough edges, alongside per-seat pricing that adds up for larger teams since there is no free tier. Higher-tier plans add dedicated customer success support and onboarding assistance, which reviewers note helps smooth over the initial setup and categorization tuning period.$q$]::text[], 4);
